SELECT count(*) FROM char_name, cast_info, title, role_type, name, aka_name, movie_companies, company_type WHERE cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id;